import jwt
from jwt import InvalidTokenError

def debug_decode_jwt(token, secret, algorithms=["HS256"]):
    try:
        decoded = jwt.decode(token, secret, algorithms=algorithms)
        return decoded
    except InvalidTokenError as e:
        print("Token verification failed:", e)
        return None

if __name__ == "__main__":
    sample_token = "your_jwt_token_here"
    secret_key = "your_secret_key_here"
    
    decoded_token = debug_decode_jwt(sample_token, secret_key)
    if decoded_token is not None:
        print("Decoded JWT payload:")
        for key, value in decoded_token.items():
            print(f"{key}: {value}")
    else:
        print("Failed to decode JWT token.")